var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"……다들 그만.","JPN":"……そこまで。","ENG":"...That's enough, everyone.","TWN":"……好了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"이 정도면 충분할 것 같구나, 로즈.","JPN":"このくらいで十分よ、ローズ。","ENG":"That should suffice, Rose.","TWN":"可以了，玫瑰。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"알겠습니다, 마스터. 전 인원 교전 중지.","JPN":"わかりました、マスター。全員、交戦中止。","ENG":"Understood, Master. All units, cease engagement.","TWN":"是的，主人。全員停止交戰。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L13_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"블랙 로즈 1개 분대, 별도 지시가 있을 때까지 대기합니다.","JPN":"ブラックローズ第1分隊、別途指示があるまで待機します。","ENG":"Black Rose, Squad One, remain on standby until further orders.","TWN":"黑玫瑰1個分隊，待命中。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_PRIDE"},"R":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아… 하아… 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff...* *Huff...* *Huff...!*","TWN":"呼……呼……呼！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 겨우 이걸로 끝이야? 어디 더 붙어 보자고……!","JPN":"くそ、これで終わりか？　こっちはまだまだ行けるけどな……！","ENG":"Damn it, that's all you got? Come on, bring it on...!","TWN":"可惡，就這樣結束了嗎？再來試試吧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"숨부터 고르고 말해요, 라이카. 호흡이 엉망이잖아요.","JPN":"息を整えてから言いなさいよ、ライカ。呼吸が乱れているわ。","ENG":"Catch your breath before yelling, Laika. You're all over the place.","TWN":"先調整呼吸再說話，萊卡。你的呼吸太亂了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러게 내가 뭐랬어요. 슬슬 다음 시즌 리그 준비하면서 몸 만들어야 한다고 했죠?","JPN":"だから言ったじゃない。そろそろ来シーズンのリーグに備えて体を鍛えないとダメだって。","ENG":"Told you, didn't I? You should've been training for next season's League.","TWN":"我就說吧。該開始準備下個賽季的聯賽，鍛煉身體了吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"후우우……! 그래, 너 잘났다, 꼬맹아!","JPN":"ふうう……！　はいはい、その通りでございます、おこちゃま！","ENG":"Phewww...! Yeah, yeah, you're so smart, kid!","TWN":"呼呼……對，你最棒了，小鬼！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"근데 내 원래 계획에 다음 시즌 같은 건 없었어. 상금이나 펑펑 쓰면서 놀 생각이었거든.","JPN":"だけど、私の本来の計画には来シーズンなんてなかったんだ。賞金をガンガン使って遊ぶつもりだったから。","ENG":"But I never planned on a next season. I was gonna blow the prize money and take it easy.","TWN":"不過我原本的計畫裡沒有下個賽季。我打算拿獎金去好好享受一下。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"なんですって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"블랙 로즈 분대의 공격을 버텨내다니…….","JPN":"ブラックローズ分隊の攻撃に耐えるなんて……","ENG":"To think you held out against the Black Rose Squad's assault...","TWN":"居然能撐過黑玫瑰分隊的攻擊……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"강아지풀 주제에 제법 분발했구나.","JPN":"エノコログサのくせに、やるじゃない。","ENG":"Not bad, Bristlegrass.","TWN":"作為狗尾草，表現得還不錯嘛。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 예상했던 것보다 최악은 아니었어. 그렇다고 아주 좋지도 않았지만 말이지.","JPN":"まあ、予想していたよりは悪くなかったわ。かといって手放しで褒められるほどでもなかったけど。","ENG":"Well, it wasn't the worst outcome. But let's not pretend it was great either.","TWN":"嗯，比預想的情況要好一些。雖然不是特別好，但至少沒有那麼糟糕。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 그 어정쩡한 칭찬은?","JPN":"なんだよ、その中途半端な褒め方？","ENG":"What kind of half-baked compliment is that?","TWN":"什麼嘛？這種不痛不癢的誇獎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나보고 어느 장단에 맞추라는 거야, 할망구?","JPN":"どう反応しろって言うんだ、ババァ。","ENG":"How am I supposed to react to that, hag?","TWN":"你讓我怎麼配合你，瘋婆子？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"일단, 임시방편으로 나이프를 섞은 격투술을 선택한 건 썩 나쁘지 않은 판단이었단다.","JPN":"まず、臨機応変にナイフを使った格闘術を選んだ点はなかなか悪くない判断だったわ。","ENG":"Choosing knife-based CQC as a stopgap wasn't a bad call.","TWN":"首先，選擇混合使用匕首的格鬥術作為權宜之計，並不是一個糟糕的判斷。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 찌르기가 너무 얕구나. 동작 하나하나가 너무 크고.","JPN":"でも、突きが浅い。ひとつひとつの動作が大きすぎる。","ENG":"But your stabs are too shallow. Every movement's too big.","TWN":"不過刺得太淺了。每個動作幅度都太大了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"맨션 메이드라는 타이틀이 아깝네. 적어도 나한테 그렇게 배우지는 않았을 텐데 말이지?","JPN":"マンションのメイドというタイトルが泣くわね。少なくとも私はそう教えなかったはずよ。","ENG":"Calling yourself a Mansion maid is a disgrace. I didn't raise you to fight like that, did I?","TWN":"真是浪費了曼森女僕這個稱號。至少我沒教過你這樣做吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시끄러워, 할망구! 누가 메이드라고……!","JPN":"うるさい、ババァ！　誰がメイドだ……！","ENG":"Shut up, hag! I'm not a maid...!","TWN":"吵死了，瘋婆子！誰說我是女僕！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 건틀렛에서 사람을 죽이면 실격 처리거든?","JPN":"それに、ガントレットでは人を殺すと失格なんだよ。","ENG":"And in the Gauntlet, killing someone gets you disqualified!","TWN":"而且在聖鎧中殺人是會被取消資格的喔？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"훈련이잖아. 급소는 피하는 게 상식이지!","JPN":"訓練だろ。急所を避けるのは常識だ！","ENG":"Plus, this is training. It's common sense to avoid vital points!","TWN":"這是訓練啊。避開要害是常識吧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래? 그것 참 편리한 변명이로구나?","JPN":"そう？　便利な言い訳だこと。","ENG":"Oh? How convenient.","TWN":"是嗎？這個藉口可真是方便好用啊？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼, 나중에 침식체를 상대로도 그렇게 말해보렴.","JPN":"だったら、後で侵食体が相手でもそう言ってみなさい。","ENG":"Try saying that when you're up against a C.O.","TWN":"那麼，之後你也可以對侵蝕體這麼說試試。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……쳇.","JPN":"……ちっ。","ENG":"...Tch.","TWN":"……嘖。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"평의회의 지원이라면, 침식체와 맞설 화력 정도는 지원받을 수 있겠지.","JPN":"評議会なら、侵食体と渡り合えるくらいの武器は支援してもらえるでしょうけど。","ENG":"With the Council's support, you'll likely get the firepower to take them on.","TWN":"只要有評議會的支持，就能獲得與侵蝕體對抗的火力支持吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 부족한 체력과 전투 센스는 당분간 맞으면서 기를 수밖에 없겠구나.","JPN":"足りない体力と戦闘センスはしばらく殴られながら育てるしかないわね。","ENG":"But your lack of stamina and combat sense will have to be drilled in through beating for now.","TWN":"不過體力不足和戰鬥感知缺少只能暫時通過挨打來提升了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그게 아니라면…….","JPN":"それとも……","ENG":"Unless...","TWN":"或者說……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 이런 방법도 있겠지.","JPN":"これを使うという手もあるけど。","ENG":"There's always this option.","TWN":"嗯，也有這種方法吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"What's this...?","TWN":"這是?"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"내가 직접 조제한 <color=#ffd34c>엘릭서</color>란다.","JPN":"私の手で作った<color=#ffd34c>エリクサー</color>よ。","ENG":"It's an <color=#ffd34c>Elixir</color>, formulated by yours truly.","TWN":"這是我親自調製的<color=#ffd34c>聖水</color>。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"시중에 불법으로 유통되는 리플레이서의 유산과는 차원이 다른 물건이지.","JPN":"世に不法に流通しているリプレイサーの遺産とは次元が違うわ。","ENG":"Far superior to those knockoff Replacer ones floating around on the black market.","TWN":"這可不是市面上非法流通的克隆集團的遺產能比的東西。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"육체 붕괴율은 최대한 낮추고, 현실개변력의 발현률은 급격히 끌어올린 특상품이야.","JPN":"肉体の崩壊率を最大限抑え、現実改変力の発現率は急激に上昇させる特上品よ。","ENG":"Minimal physical degradation, and maximum boost to Counter Reality Force potential.","TWN":"這是特製品，不僅儘量降低肉體崩潰率，並且大幅提高現實改變力的觸發率。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"이것만 있다면, 평범한 인간도 카운터처럼 싸울 수 있단다.","JPN":"これさえあれば、普通の人間もカウンターのように戦える。","ENG":"With this, even a normal human could fight like a Counter.","TWN":"只要有這個，普通人也能像制裁者一樣戰鬥。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이게 그 엘릭서라고……?","JPN":"これがあのエリクサー……？","ENG":"This is the Elixir...?","TWN":"這就是所謂的聖水嗎？"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"물론이야. 이래봬도 나는 재능론자가 아니란다.","JPN":"そうよ。こう見えても私は才能論者ではないもの。","ENG":"Of course. I'm not one to rely on talent alone.","TWN":"當然，我可不是個天賦論者。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"재능이 부족하다면, 어떤 식으로든 외부로부터 끌어오면 그만이지.","JPN":"才能が足りないのなら、どんな手を使ってでも外部から持ってくればいいだけ。","ENG":"If you lack talent, just borrow from elsewhere.","TWN":"如果缺乏才能，就從外部以某種方式導入就好。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그게 돈이든, 기술이든, 약물이든 하물며 육체를 개조하는 시술이든…….","JPN":"それがお金だろうと技術だろうと薬物だろうと、肉体を改造する施術だろうと……","ENG":"Whether it's money, tech, drugs, or body mods...","TWN":"無論是錢、技術、藥物，甚至是改造身體的手術……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"리스크만 짊어질 수 있다면, 평범한 자들도 강해질 수 있는 수단은 얼마든지 있단다.","JPN":"リスクさえ負うことができるなら、普通の人でも強くなれる方法はいくらでもあるわよ。","ENG":"As long as you can shoulder the risk, there are plenty of ways for the ordinary to become strong.","TWN":"只要能承擔風險，普通人也有很多變強的方法。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그렇지 않으면, 이 세상이 너무 불공평하다고 생각하지 않니?","JPN":"でないと、この世界はあまりにも不公平だと思わない？","ENG":"Otherwise, this world's just too unfair, wouldn't you agree?","TWN":"否則，你不覺得這個世界太不公平了嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"어떠니, 강아지풀?","JPN":"どうかしら、エノコログサ。","ENG":"So, what do you say, Bristlegrass?","TWN":"怎麼樣，狗尾草？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"너와 나 사이라면, 앰풀 몇 개 정도는 값을 치르지 않고 줄 수도 있단다.","JPN":"あなたと私の仲だもの、アンプルのいくつかくらいはタダであげられるわ。","ENG":"Since you and I go back, I could give you a few ampoules free of charge.","TWN":"如果是你和我之間的關係，我可以免費給你幾支樣品。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"물론, 리스크는 따르겠지만, 네 수준에서 짧은 시간에 강해지려면 이정도 밖에…….","JPN":"もちろんリスクはあるでしょうけど、今のあなたが短い時間で強くなるためにはこれしか……","ENG":"Sure, there's a risk. But if you want power fast, that's about the only way...","TWN":"當然，雖然會有風險，但在你的水準上，想在短時間內變強只能這樣……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……집어치워, 할망구.","JPN":"……いい加減にしろよ、ババァ。","ENG":"...Forget it, hag.","TWN":"……不必了，瘋婆子。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"누굴 반병신 만들려고. 맨션에서 그거 빨고 맛탱이 간 녀석들을 한두 번 본 줄 알아?","JPN":"廃人なんてごめんだね。マンションでそれ飲んでおかしくなったやつらをたくさん見てきたんだ。","ENG":"Trying to cripple me? I've seen too many Mansion junkies lose their minds on that stuff.","TWN":"你想把誰變成半殘廢？你以為我沒見過在曼森裡吸那個東西然後變得瘋瘋癲癲的人嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내 일은 내가 알아서 해. 그러니까 약 장사할 생각은 집어치워.","JPN":"私の人生は私が選択する。だから薬を売りつけようなんて考えは捨てな。","ENG":"I'll handle my own business. So save your snake oil for someone else.","TWN":"我的事情我自己會處理，你別想動歪腦筋。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"우후훗, 역시나 그 고집은 여전하구나.","JPN":"うふふっ、やっぱり頑固なところは変わらないわね。","ENG":"Uhu huu. That stubborn streak of yours hasn't changed one bit.","TWN":"呵呵，你還是那麼固執啊。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"못 써먹을 잡초 주제에 그런 부분은 제법 억세단 말이지.","JPN":"使い道のない雑草のくせに、そんなところはたくましいんだから。","ENG":"Such a pain to deal with, for a useless weed.","TWN":"作為無用的雜草，倒是有些頑強的地方。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 그런 점이 강아지풀 네 귀여운 점이지만…….","JPN":"まあ、そこがエノコログサの可愛いところなんだけど……","ENG":"But I suppose that's part of your charm, Bristlegrass...","TWN":"嗯，這也是狗尾草可愛的地方……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼, 어쩌겠니? 가장 효율성이 떨어지는 노력이라도 할 수밖에.","JPN":"仕方ないわね。一番効率の悪い、努力でもしてもらうしか。","ENG":"Well then, what other choice is there? You'll just have to stick with the least efficient route of putting in the effort.","TWN":"那又能怎麼辦呢？只好做些成效不佳的努力囉。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"으으! 강아지풀, 강아지풀…! 시끄러워 죽겠네……!","JPN":"エノコログサ、エノコログサ……！　うるさいんだよ……！","ENG":"Ugh! Bristlegrass, Bristlegrass...! You never shut up...!","TWN":"哼！狗尾草，狗尾草！吵死了！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 엘릭서인지 뭔지 없이도, 내가 요 꼬맹이 하나 못 지킬 것 같아?","JPN":"そのエリクサーとやらがなくても、おこちゃまのひとりくらいは守れる！","ENG":"You think I need that Elixir or whatever to protect this kid?","TWN":"沒有那個什麼聖水，我就保護不了這個小鬼嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"닥치고, 얌전히 지켜보기나 하라고! 이 망할 할망구……!","JPN":"黙って、大人しく見てろよ！　このクソババァ……！","ENG":"Just shut it and watch! Damn hag...!","TWN":"閉嘴，乖乖看著吧！你這個臭瘋婆子！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"가자, 꼬맹이! 이번에는 제대로 보여줄 테니까!","JPN":"行こう、おこちゃま！　今度は完璧にやってみせる！","ENG":"Let's go, kid! This time, I'll show you what I'm made of!","TWN":"走吧，小鬼！這次我要好好展示給你看！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"알겠어요, 라이카!","JPN":"わかったわ、ライカ！","ENG":"Okay, Laika!","TWN":"知道了，萊卡！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"후후, 역시 잡초라고는 해도 꽃은 꽃이려나?","JPN":"ふふ、やっぱり雑草と言えども、花は花かしらね。","ENG":"Fu fu, maybe even a weed can bloom into a flower after all.","TWN":"呵呵，也許連野草最終也能開出花來呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"비록 건방지긴 해도, 제법 끈질긴 게 구경하는 보람은 있구나.","JPN":"生意気だけど、なかなか根気があるところは見ていて楽しいわ。","ENG":"She's still a mouthy little thing, but there's something satisfying about her tenacity.","TWN":"雖然有些自大，但還蠻有韌性的，值得一看呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 길들일 수 없는 꽃을 길들인다는 건, 정원사로서 기쁜일이지만.","JPN":"まあ、手懐けられない花を手懐けるのは、庭師として嬉しいことだけれど。","ENG":"And there's joy in taming a flower no one else can. That's what makes a gardener's life worthwhile.","TWN":"嗯，馴服一朵無法馴服的花朵，作為園丁來說是件令人開心的事。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};